// src/components/Button/index.ts
export { Button } from './Button';
export type { ButtonProps } from './Button';

// vite.config.ts
import { defineConfig } from 'vite';
import react from '@vitejs/plugin-react';
import path from 'path';

export default defineConfig({
  plugins: [react()],
  resolve: {
    alias: {
      '@': path.resolve(__dirname, './src'),
    },
  },
});

// 1. Imports (external first, then internal)
import { useState, useCallback } from 'react';
import { formatDate } from '@/utils/formatDate';
import styles from './UserCard.module.css';

// 2. Types / interfaces
interface UserCardProps {
  userId: string;
  onDelete: (id: string) => void;
}

// 3. Helper functions used only by this component
function initials(name: string) {
  return name.split(' ').map(w => w[0]).join('');
}

// 4. The component (exported, named)
export function UserCard({ userId, onDelete }: UserCardProps) {
  const [expanded, setExpanded] = useState(false);

  const handleDelete = useCallback(() => {
    onDelete(userId);
  }, [userId, onDelete]);

  return (
    <div className={styles.card}>
      <button onClick={() => setExpanded(e => !e)}>Toggle</button>
      {expanded && <p>ID: {userId}</p>}
      <button onClick={handleDelete}>Delete</button>
    </div>
  );
}

// 5. Default export (optional — named exports are easier to refactor)
export default UserCard;

// src/components/index.ts — convenient but can slow HMR
export * from './Button';
export * from './Input';
export * from './Modal';
export * from './DataTable';  // 500-line component
// ... 30 more exports

// Consumer
import { Button } from '@/components'; // triggers processing of ALL components

// Presentational — easy to test, just render and check output
function UserCard({ name, email, onDelete }: UserCardProps) {
  return (
    <div>
      <p>{name}</p>
      <p>{email}</p>
      <button onClick={onDelete}>Delete</button>
    </div>
  );
}

// Container — wires data and behaviour
function UserCardContainer({ userId }: { userId: string }) {
  const { user, deleteUser } = useUser(userId);
  if (!user) return <Spinner />;
  return <UserCard name={user.name} email={user.email} onDelete={() => deleteUser(userId)} />;
}

// src/constants/routes.ts
export const ROUTES = {
  home:          '/',
  products:      '/products',
  productDetail: (id: string) => `/products/${id}`,
  cart:          '/cart',
  login:         '/login',
} as const;

// Usage
import { ROUTES } from '@/constants/routes';
<Link to={ROUTES.productDetail(product.id)}>View</Link>

// vite.config.ts
import { resolve } from 'path';

resolve: {
  alias: {
    '@':          resolve(__dirname, 'src'),
    '@components': resolve(__dirname, 'src/components'),
    '@features':   resolve(__dirname, 'src/features'),
    '@utils':      resolve(__dirname, 'src/utils'),
    '@assets':     resolve(__dirname, 'src/assets'),
  },
}
